package com.cho2hand.marketplace.entity.trust; import jakarta.persistence.*; import java.time.Instant;
@Entity @Table(name="seller_reviews") public class SellerReview {@Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="review_id") private Long id;@Column(name="transaction_id") private Long transactionId;@Column(columnDefinition="tinyint unsigned") private short rating;private String body;private String status;@Column(name="created_at") private Instant createdAt;@Column(name="updated_at") private Instant updatedAt;@PrePersist void created(){createdAt=updatedAt=Instant.now();status="VISIBLE";}@PreUpdate void updated(){updatedAt=Instant.now();}public void setTransactionId(Long v){transactionId=v;}public void setRating(short v){rating=v;}public void setBody(String v){body=v;}}
